      "content": "const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', async (req, res) => {
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_MESSAGE', 'Message is required');
  }

  const comment = await service.createComment(req.params.projectId, req.params.taskId, message);
  if (!comment) {
    return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to create comment');
  }

  res.status(201).json({ comment });
});

router.get('/', async (req, res) => {
  const comments = await service.getComments(req.params.projectId, req.params.taskId);
  if (!comments) {
    return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to fetch comments');
  }

  res.json({ comments });
});

module.exports = router;
