      "content": "const express = require('express');
const service = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', async (req, res) => {
  const task = await service.createTask(req.params.projectId);
  if (!task) {
    return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to create task');
  }

  res.status(201).json({ task });
});

router.get('/', async (req, res) => {
  const tasks = await service.getTasks(req.params.projectId);
  if (!tasks) {
    return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to fetch tasks');
  }

  const statusFilter = req.query.status;
  if (statusFilter) {
    res.json({ tasks: tasks.filter(task => task.status === statusFilter) });
  } else {
    res.json({ tasks });
  }
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Status must be either todo or done');
  }

  const task = await service.updateTask(req.params.projectId, req.params.taskId, status);
  if (!task) {
    return sendError(res, 500, 'INTERNAL_ERROR', 'Failed to update task');
  }

  res.json({ task });
});

module.exports = router;
