      "path": "src/modules/tasks/service.js",
      "content": "const { generateId } = require('../../lib/id');
let projectsStore = require('../projects/service').projectsStore;

const createTask = (projectId) => {
  const project = projectsStore[projectId];
  if (!project) return null;

  const task = { id: generateId(), status: 'todo' };
  project.tasks.push(task);
  return task;
};

const getTasks = (projectId) => {
  const project = projectsStore[projectId];
  if (!project) return null;

  return project.tasks;
};

const updateTask = (projectId, taskId, status) => {
  const project = projectsStore[projectId];
  if (!project) return null;

  const task = project.tasks.find(task => task.id === taskId);
  if (!task) return null;

  task.status = status;
  return task;
};

module.exports = { createTask, getTasks, updateTask };
